import React from "react"
import styled from "styled-components"
import { graphql } from "gatsby"

import Layout from "../components/layout"
import SEO from "../components/seo"

const PostHeader = styled.div`
  background-color: #3a91ee;
  color: #fff;
  text-align: center;
  padding: 100px 50px;
  line-height: 1.3;
  word-break: keep-all;
`
const Title = styled.div`
  font-weight: 700;
  font-size: 30px;
`
const Wrap = styled.div`
  width: 100%;
  max-width: 840px;
  margin: 0 auto;
  padding: 0;
`
const Apps = styled.div`
  display: flex;
  flex-direction: column;
  flex-wrap: wrap;
  justify-content: space-between;
  width: 100%;
  height: auto;
  padding: 16px;
`
const App = styled.a`
  display: flex;
  flex: 1;
  border-radius: 8px;
  background-color: #ffffff;
  margin-bottom: 16px;
  box-shadow: 0px 2px 4px 0px rgb(0 0 0 / 8%);
  transition: transform 250ms ease-in-out;
  &:hover {
    transform: translateY(-4px);
  }
`
const AppThumbnail = styled.div`
  flex: 0 0 120px;
  border-radius: 8px 0 0 8px;
  border-right: 1px solid #f1f1f1;
  width: 120px;
  height: 120px;
  background-color: ${props => props.backgroundColor || "#3a91ee"};
  background-image: ${props => props.backgroundImage || ""};
  background-size: contain;
  background-repeat: no-repeat;
  display: flex;
  justify-content: center;
  align-items: center;
  color: #ffffff;
  font-size: 28px;
  font-weight: bold;
`
const AppContent = styled.div`
  padding: 16px;
`
const AppTitle = styled.div`
  font-size: 24px;
  font-weight: bold;
  margin-bottom: 8px;
`
const AppDescription = styled.div`
  font-size: 16px;
`

class BlogIndex extends React.Component {
  render() {
    const { data } = this.props
    const siteTitle = data.site.siteMetadata.title
    const apps = [
      {
        title: "디에디톡",
        description: "iMessage 스타일의 채팅 스크린샷을 만듭니다.",
        link: "https://github.com/jyqry/the-edit-talk",
        backgroundColor: "#ffffff",
        backgroundImage: `url(/image/apps/the-edit-talk.jpg)`,
      },
      {
        title: "새로나왔",
        description: "인스타그램 스타일의 이미즈를 만듭니다.",
        link: "https://github.com/jyqry/the-edit-new",
        backgroundColor: "#ffffff",
        backgroundImage: `url(/image/apps/the-edit-new.jpg)`,
      },
      {
        title: "SLUMP",
        description: "좋아하는 것을 검색하고 화면을 멍하니 바라보세요.",
        link: "http://slump.chichi.space/",
        backgroundColor: "#ffcc00",
        backgroundImage: "",
      },
    ]
    return (
      <Layout location={this.props.location} title={siteTitle}>
        <SEO title="치치스페이스" />
        <PostHeader>
          <Title>Apps</Title>
        </PostHeader>
        <Wrap>
          <Apps>
            {apps.map(app => (
              <App key={app.title} href={app.link} target="_blank">
                <AppThumbnail
                  backgroundColor={app.backgroundColor}
                  backgroundImage={app.backgroundImage}
                >
                  {!app.backgroundImage && app.title}
                </AppThumbnail>
                <AppContent>
                  <AppTitle>{app.title}</AppTitle>
                  <AppDescription>{app.description}</AppDescription>
                </AppContent>
              </App>
            ))}
          </Apps>
        </Wrap>
      </Layout>
    )
  }
}

export default BlogIndex

export const pageQuery = graphql`
  query {
    site {
      siteMetadata {
        title
      }
    }
  }
`
